const query = ($json.query || '').toString().trim();
const source = ($json.source || 'nanoclaw').toString();
const agentId = ($json.agentId || 'dolphin').toString();
const apiKey = ($json.tavily_api_key || '').toString().trim();

if (!query) {
  return [{ json: { query, source, agentId, answer: '', results: [], error: 'query is empty' } }];
}

if (!apiKey) {
  return [{ json: { query, source, agentId, answer: '', results: [], error: 'Tavily API key missing in request body' } }];
}

try {
  const response = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.tavily.com/search',
    body: {
      api_key: apiKey,
      query,
      search_depth: 'basic',
      max_results: 6,
      include_answer: true,
      topic: 'general',
    },
    json: true,
  });

  return [{
    json: {
      query,
      source,
      agentId,
      answer: response.answer || '',
      results: Array.isArray(response.results) ? response.results : [],
      error: '',
    },
  }];
} catch (e) {
  return [{
    json: {
      query,
      source,
      agentId,
      answer: '',
      results: [],
      error: `Tavily request failed: ${String(e.message || e)}`,
    },
  }];
}

const query = ($json.query || '').toString().trim();
const source = ($json.source || 'nanoclaw').toString();
const agentId = ($json.agentId || 'dolphin').toString();
const answer = ($json.answer || '').toString();
const error = ($json.error || '').toString();
const results = Array.isArray($json.results) ? $json.results : [];

const lines = [];
lines.push('=== 웹 리서치 결과 ===');
lines.push(`query: ${query}`);
lines.push(`source: ${source}`);
lines.push(`agentId: ${agentId}`);
lines.push(`generated_at: ${new Date().toISOString()}`);
lines.push('');

if (error) {
  lines.push('⚠️ 검색 오류');
  lines.push(error);
  lines.push('');
}

if (answer) {
  lines.push('요약 답변');
  lines.push(answer);
  lines.push('');
}

if (!results.length) {
  lines.push('검색 결과가 없습니다.');
} else {
  lines.push('근거 출처');
  for (const [index, item] of results.slice(0, 6).entries()) {
    const title = (item.title || 'Untitled').toString().trim();
    const url = (item.url || '').toString().trim();
    const snippet = (item.content || item.snippet || '').toString().replace(/\s+/g, ' ').trim();

    lines.push(`${index + 1}. ${title}`);
    if (url) lines.push(`- url: ${url}`);
    if (snippet) lines.push(`- summary: ${snippet}`);
    lines.push('');
  }
}

const filename = `research_${Date.now()}.txt`;

return [{
  json: {
    final_text: lines.join('\n').trim(),
    filename,
  },
}];
